export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:22。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "燈滅了。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是閃爍。不是漸暗。是同時。鐘樓裡僅剩的應急照明、他手機的手電筒、甚至齒輪機械上那一排指示燈——全部在同一瞬間熄滅。像有人按下了一個開關。不是停電。是關機。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)黑了。", background: "chapter_1/ch1_act10_s0", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)全部黑了。手機也——", background: "chapter_1/ch1_act10_s0", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他按了兩下電源鍵。螢幕沒有亮。他的手指在黑暗中摸索著手機的側面，確認按鍵有彈性、玻璃面板是冷的、沒有碎裂。手機沒有壞。它只是不亮了。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不可能同時壞掉。手機和鐘樓的照明不可能同時——", background: "chapter_1/ch1_act10_s0", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鐘鳴了。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是報時的那種悠長鐘聲。是整座鐘體在震動。從他腳下的金屬走道傳上來，穿過鞋底，穿過骨頭，一直震到牙齒。嗡嗡嗡嗡嗡。低頻的、密集的、像一台巨大的發動機在他體內啟動。雨從鐘面的縫隙灌進來，不是滴落，是傾瀉。冰涼的水柱打在他的頭頂、肩膀、手背。三秒之內，他從微濕變成了全身浸透。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他聽到了腳步聲。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是從遠處傳來的。是從他正前方。兩公尺。那個黑色雨衣的人動了。在完全的黑暗裡，他看不到任何東西，但腳步聲告訴他一切——嗒、嗒、嗒——在朝他的方向走來。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在過來。", background: "chapter_1/ch1_act10_s0", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在——", background: "chapter_1/ch1_act10_s0", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一雙手推在他的胸口。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "力量不大。甚至可以說是精準的。不是打擊，不是毆打。是推。重心偏移的推。位置恰好在胸骨正中，角度微微向上，讓他的上半身向後仰，腳下的重心瞬間失控。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)！", background: "chapter_1/ch1_act10_s0", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的右手在空中劃了一圈，手指碰到了什麼——金屬。欄杆。檢修平台外側的安全欄杆。他抓住了。五根手指死死地扣住欄杆的橫管，指節發白，手臂的肌肉在瞬間繃成了鋼纜。身體的重量全部掛在了右手上。腳離開了走道。懸在半空中。雨打在他的背上，像無數根冰冷的針。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他撐住了。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)撐住了。", background: "chapter_1/ch1_act10_s0", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我撐——", background: "chapter_1/ch1_act10_s0", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "欄杆鬆了。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是斷裂。是位移。他右手抓住的那段欄杆，底部的固定螺絲——右側的兩顆——沒有咬合。螺絲孔是空的。螺絲已經被提前卸掉了。欄杆在他抓握的拉力下向外傾斜，金屬根部發出了一聲短促的、不情願的嘎吱聲。然後左側僅剩的螺絲也開始滑動。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)螺絲。", background: "chapter_1/ch1_act10_s0", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)被卸掉了。早就被卸掉了。", background: "chapter_1/ch1_act10_s0", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這是——", background: "chapter_1/ch1_act10_s0", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "欄杆脫離了平台。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他和欄杆一起向外傾倒。在那一瞬間，他的左手在空中亂抓，指尖擦過了走道邊緣的金屬板，觸感冰冷而光滑，沒有任何可以抓住的東西。他的身體離開了平台。雨從四面八方包圍了他。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.BlackRaincoat, character: "黑雨衣", dialogue: "他還沒想起來。", background: "chapter_1/ch1_act10_s0", portrait: Portrait.BlackRaincoat_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音從上面傳下來。很近。就在他剛才站的位置。那個成年男人的聲音，平靜得像在陳述一個氣象預報。不帶感情。不帶惡意。只是一個事實。", background: "chapter_1/ch1_act10_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他在墜落。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有聲音。或者有聲音但他聽不到了。雨聲、鐘聲、齒輪聲全部消失。世界變成了一個純粹的、失重的、黑暗的空間。他的胃像被一隻手從裡面揪起來。風從下面湧上來，灌進他的衣服、袖口、領口，把他變成了一個被吹脹的、空洞的形狀。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我在掉下去。", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)鐘樓。掉。四層。或者五層。不知道。黑暗。不知道還要掉多久。", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手機亮了。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕在黑暗中像一顆突然睜開的眼睛。白光刺目。他沒有去按它。它自己亮了。螢幕上顯示著鎖定畫面：22:22。沒有通知。沒有訊息。只有時間。那個數字在黑暗中發著冷白色的光，像一塊嵌入虛空的墓碑。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)22:22。", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)早上的訊息。「今晚 22:22，鐘樓會停電。不要上去。」", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我沒有救任何人。我甚至沒有救自己。", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這不是惡作劇。", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是惡作劇。照片。鐘樓。螺絲。從來都不是。有人在殺我。", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)有人要殺我。", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)而我到現在才明白。", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "恐懼在某一刻達到了頂點。然後——奇怪地——開始消退。不是因為勇氣。是因為感官開始飽和。大腦在處理太多不可能同時發生的事情。墜落、黑暗、雨、冷、22:22、那個聲音、那句話。太多。超載。他的意識像一台過熱的電腦，開始關閉非必要的進程，只留下最核心的、最原始的、最無法關閉的那個——活著的感覺。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看到了鐘面。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是用眼睛看的。是某種感覺。巨大的羅馬數字在黑暗中翻轉，像一副被打亂的紙牌。時針和分針交叉成銳角，指向同一個方向。鐘面在轉。不是鐘在轉——是他在轉。他的身體在墜落中旋轉，世界在他的視網膜上畫出一個又一個模糊的圓。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後——", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "有什麼東西落入了他的掌心。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是雨。不是碎片。是一個固體的、有重量的、帶棱角的東西。小。大約兩公分寬。薄。像一張卡片。有人——或者沒有人——把它按進了他張開的左手掌心。手指被按壓合攏，包住了那個東西。力道很輕。很確定。像一個習慣了遞東西給別人的人的動作。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "記憶卡。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不知道自己怎麼知道的。但他知道了。掌心裡那個冰冷的、帶著塑料觸感的小東西，是一張記憶卡。這不是判斷。不是推理。是知道。像他一直知道、只是忘了自己知道的事情。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.FemaleVoice, character: "女聲", dialogue: "不要只救⋯⋯", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音。從很遠的地方。或者從很近的地方。從他的腦海裡。從雨裡。從鐘的嗡鳴裡。那個聲音——年輕的、女性的、帶著一種急切的、被截斷的語調——在他的意識裡炸開。不是回憶。是他從來沒有聽過的聲音。但他認識那個聲音。他的身體認識。他的後頸豎起了汗毛。他的心臟跳了一下——不是因為恐懼，是因為某種更深層的、他無法命名的東西。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不要只救——什麼？", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不要只救什麼？", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "快門聲。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "從頭頂。從鐘面。從黑暗中的某個位置。一聲相機快門的聲音。清脆的。機械的。像槍響。在這個封閉的、垂直的、被雨水灌滿的空間裡，那聲快門像一把刀切開了所有的雨聲、風聲、鐘聲。他的大腦在那一聲中被定住了。畫面凍結。時間凍結。他懸在半空中，手裡攥著一張不知道從哪裡來的記憶卡，耳邊迴響著一句不完整的話。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後一切都暗了。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是漸暗。不是閉眼。是黑。純粹的、完整的、沒有任何光源的黑。沒有雨。沒有風。沒有重量。沒有聲音。他存在，但他什麼都感覺不到。他思考，但他的思緒像水一樣從指縫間流走。最後一個清晰的念頭浮上來，又被黑暗吞沒。", background: "chapter_1/ch1_act10_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我還沒有——", background: "chapter_1/ch1_act10_s1", portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑。", background: "chapter_1/ch1_act10_s1" },
];
